SELECT product_id AS productId, category_id AS categoryId, product_name AS productName, product_image_url AS productImageUrl, price AS price, description AS description FROM products WHERE use_yn = 'Y'
AND category_id = #{categoryId}
AND ( product_name LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') )
AND price >= #{minPrice}
AND price <= #{maxPrice}
ORDER BY product_id DESC
